
.status-bar {
  width: 100%;
  max-width: 480px;
  margin: 0 auto;
  background-color: var(--c-surface);
  border: 1px solid var(--c-border);
  border-radius: 10px;
  padding: 14px 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  font-size: 13px;
  color: var(--c-text);
  line-height: 1.4;
}

.header {
  display: flex;
  align-items: center;
  gap: 8px;
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;

  &.accent {
    background-color: var(--c-primary);
  }
}

.title {
  font-weight: 600;
  font-size: 14px;
  color: var(--c-text);
}

.stats {
  display: flex;
  align-items: center;
  gap: 20px;
  flex-wrap: wrap;
}

.stat-item {
  display: flex;
  align-items: center;
  gap: 6px;
}

.stat-label {
  color: var(--c-text-muted);
  font-size: 12px;
}

.stat-value {
  color: var(--c-text);

  &.follower {
    font-weight: 600;
    color: var(--c-primary);
  }
}

.live-item {
  .live-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background-color: var(--c-live);
    animation: pulse 2s ease-in-out infinite;
  }

  .live-text {
    color: var(--c-live);
    font-weight: 600;
    font-size: 12px;
  }
}

.commissions {
  display: flex;
  flex-direction: column;
  gap: 6px;
  border-top: 1px solid var(--c-border);
  padding-top: 10px;
}

.section-label {
  font-size: 11px;
  color: var(--c-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.commission-row {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 13px;
}

.commission-client {
  font-weight: 500;
  color: var(--c-text);
}

.commission-sep {
  color: var(--c-text-muted);
}

.commission-content {
  color: var(--c-text-muted);
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}
